import{_ as e,o as r,c as i,a3 as t}from"./chunks/framework.BlfGB29P.js";const f=JSON.parse('{"title":"XiHan.BasicApp 基础应用","description":"","frontmatter":{},"headers":[],"relativePath":"cosmos/basic-app/index.md","filePath":"cosmos/basic-app/index.md","lastUpdated":1783773945000}'),n={name:"cosmos/basic-app/index.md"};function o(l,a,s,h,p,d){return r(),i("div",null,[...a[0]||(a[0]=[t('<h1 id="xihan-basicapp-基础应用" tabindex="-1">XiHan.BasicApp 基础应用 <a class="header-anchor" href="#xihan-basicapp-基础应用" aria-label="Permalink to &quot;XiHan.BasicApp 基础应用&quot;">​</a></h1><p><strong>企业级中后台内核。</strong> 后端基于 .NET 10 与 <a href="./../framework/">XiHan.Framework</a>，前端基于 Vue 3，开箱即带多租户、RBAC + ABAC 权限、代码生成与实时通信等能力。它既是一套可直接投产的中后台起点，也是学习 .NET + Vue 全栈实践、以及 XiHan.Framework 用法的最佳参考。</p><h2 id="它是什么" tabindex="-1">它是什么 <a class="header-anchor" href="#它是什么" aria-label="Permalink to &quot;它是什么&quot;">​</a></h2><p>XiHan.BasicApp 采用<strong>前后端分离</strong>架构：</p><ul><li><strong>后端</strong> 遵循 DDD 分层与 CQRS，应用服务经<strong>动态 API</strong> 直接暴露为 REST 接口，无需写 Controller</li><li><strong>前端</strong> 使用 Vue 3 + TypeScript + Naive UI，Schema 驱动的列表页、权限/租户/偏好三重感知</li></ul><p>系统内置完整的身份、权限、租户与审计能力。你可以拿它当项目脚手架直接改，也可以只读它的代码学习框架怎么用。</p><h2 id="从这里开始" tabindex="-1">从这里开始 <a class="header-anchor" href="#从这里开始" aria-label="Permalink to &quot;从这里开始&quot;">​</a></h2><div class="tip custom-block" style="padding-top:8px;"><ol><li><a href="./getting-started"><strong>快速开始</strong></a> —— 在本地把前后端跑起来（约 10 分钟）</li><li><a href="./architecture"><strong>系统架构</strong></a> —— 看懂后端模块划分与前后端协作</li><li><a href="./permissions"><strong>权限模型</strong></a> —— 理解 RBAC + ABAC、数据范围、多租户隔离</li></ol></div><h2 id="文档地图" tabindex="-1">文档地图 <a class="header-anchor" href="#文档地图" aria-label="Permalink to &quot;文档地图&quot;">​</a></h2><p><strong>开始</strong></p><ul><li><a href="./overview">系统概述</a> —— 定位、技术栈、能力全景</li><li><a href="./getting-started">快速开始</a> —— 环境要求、后端 / 前端 / 数据库启动、默认账号</li></ul><p><strong>架构与二次开发</strong></p><ul><li><a href="./architecture">系统架构</a> —— 分层、模块（Saas / CodeGeneration / AI）、动态 API、菜单单一事实源、缓存</li><li><a href="./frontend">前端指南</a> —— Schema 驱动列表页、三级权限、国际化 / 时区、实时通信</li><li><a href="./development">二次开发</a> —— 加功能纵切片 / 加独立模块 / 加前端页</li></ul><p><strong>核心能力</strong></p><ul><li><a href="./identity">身份与认证</a> —— 用户 / 角色 / 部门 / 菜单、多种登录、JWT 双令牌、2FA</li><li><a href="./permissions">权限模型</a> —— RBAC + ABAC、权限码、数据范围、字段脱敏、版本门控</li><li><a href="./multi-tenancy">多租户与版本</a> —— 字段级隔离、租户切换、版本（Edition）门控</li><li><a href="./messaging">消息中心</a> —— 五类消息、模板、四渠道扇出、SignalR 通知与聊天</li><li><a href="./audit-log">审计日志</a> —— 六类日志、自动脱敏、实体变更留痕</li><li><a href="./code-generation">代码生成</a> —— 单表 / 树形 / 主从、全栈一键生成</li><li><a href="./ai">AI 能力</a> —— Provider 库化管理、RAG 知识库、Agent / MCP</li></ul><p><strong>参考</strong></p><ul><li><a href="./features">功能清单</a> —— 完整能力清单</li><li><a href="./deployment">部署</a> —— Linux systemd / Windows 部署</li><li><a href="./changelog">更新日志</a> —— 各版本变更记录</li></ul><h2 id="技术栈速览" tabindex="-1">技术栈速览 <a class="header-anchor" href="#技术栈速览" aria-label="Permalink to &quot;技术栈速览&quot;">​</a></h2><table tabindex="0"><thead><tr><th>端</th><th>关键技术</th></tr></thead><tbody><tr><td>后端</td><td>.NET 10 · XiHan.Framework 3.5.0 · SqlSugar（PostgreSQL/MySQL/MariaDB）· Redis · SignalR · Serilog · Scalar</td></tr><tr><td>前端</td><td>Vue 3.5+ · TypeScript 6.0+ · Vite 8 · Naive UI · Pinia · Tailwind CSS 4 · Tiptap · vue-i18n</td></tr></tbody></table><h2 id="在线体验" tabindex="-1">在线体验 <a class="header-anchor" href="#在线体验" aria-label="Permalink to &quot;在线体验&quot;">​</a></h2><ul><li><strong>在线用例</strong>：<a href="https://basicapp.xihanfun.com" target="_blank" rel="noreferrer">https://basicapp.xihanfun.com</a></li><li><strong>源码</strong>：<a href="https://github.com/XiHanFun/XiHan.BasicApp" target="_blank" rel="noreferrer">GitHub</a> · <a href="https://gitee.com/XiHanFun/XiHan.BasicApp" target="_blank" rel="noreferrer">Gitee</a></li></ul><h2 id="与-xihan-framework-的关系" tabindex="-1">与 XiHan.Framework 的关系 <a class="header-anchor" href="#与-xihan-framework-的关系" aria-label="Permalink to &quot;与 XiHan.Framework 的关系&quot;">​</a></h2><p>XiHan.BasicApp 构建在 <a href="./../framework/">XiHan.Framework</a> 之上——框架提供认证、授权、数据、缓存、事件总线、多租户、动态 API 等底层能力，BasicApp 在其上实现具体的中后台业务。想先理解底层机制，建议先读<a href="./../framework/quickstart">框架快速上手</a>。</p>',23)])])}const g=e(n,[["render",o]]);export{f as __pageData,g as default};
